        var tmp = [];
        if (this.height == 1){
            for (var i = 0 ; i < this.width ; i++){
                tmp[i] = [];
                tmp[i][0] = this.value[0][i];
            }
        } else {
            tmp = [[]];
            for (var i = 0 ; i < this.height ; i++){
                tmp[0][i] = this.value[i][0];
            }
        }
        this.value = tmp;
        tmp = this.width;
        this.width = this.height;
        this.height = tmp;
    }
    /**
     * @method
     * @function each
     * @desc For each this vector.
     */
    each(callback){
        if (this.height == 1){
            for (var i = 0 ; i < this.width ; i++){
                callback(i,this.value[0][i]);
            }
        } else {
            for (var i = 0 ; i < this.height ; i++){
                callback(i,this.value[i][0]);
            }
        }
    }
}

