import * as number from "./lib/number";

/**
 * Sigma function
 */
export function sigma(exp: string, count: number, init: SigmaInit): number {
    let sum = 0;
    let newExp: string;
    let currentValue = init.value;

    for (let i = 0; i < count; i++) {
        newExp = exp.replace(new RegExp(init.name, 'g'), currentValue.toString());
        sum += (expression(newExp) as number);
        currentValue++;
    }
    return sum;
}

/**
 * Parse the expression of the string arithmetic and get the result.
 */
export function expression(exp: string): number | number[] {
    const lines: string[] = exp.split("\n");
    const exps: string[] = exp.split(/={5}/g);

    if (exps.length > 1) {
        // Many expressions
        const reses: number[] = [];
        for (let i = 0; i < exps.length; i++) {
            const result = expression(exps[i]);
            if (typeof result === 'number') {
                reses.push(result);
            }
        }
        return reses;
    } else {
        // Check for Sigma or Fraction formats
        if (exp.search(/[_\\]/g) === -1 &&
            exp.search(/[a-zA-z]\s*\([\s\S]*\)\s*=/g) === -1 &&
            exp.search(/={2}/g) === -1 &&
            exp.search(/-{2}/g) === -1) {

            // Four arithmetic operation (The core Stack-based parser)
            exp = exp.replace(/\(\s*(-\d+\.{0,1}\d*\s*)\)/g, "0" + "$1");

            const optArr: OptPriority[] = [
                { opt: '+', priority: 1 },
                { opt: '-', priority: 1 },
                { opt: '*', priority: 2 },
                { opt: '/', priority: 2 },
                { opt: '%', priority: 2 },
            ];

            const priority = (opt: string): number => {
                for (let i = 0; i < optArr.length; i++) {
                    if (opt == optArr[i].opt)
                        return optArr[i].priority;
                }
                return -1;
            };

            const isNum = (c: string): boolean => {
                return c == '√' || (c >= '0' && c <= '9') || (c >= "a" && c <= "z");
            };

            const toNum = (str: string, pos: number): NumResult => {
                let sztmp = "";
                let currentPos = pos;

                // Loop while char is letter, digit, dot, or power symbol
                while (currentPos < str.length &&
                    ((str[currentPos] >= "a" && str[currentPos] <= "z") ||
                        (str[currentPos] >= '0' && str[currentPos] <= '9') ||
                        str[currentPos] == '.' ||
                        str[currentPos] == "^")) {
                    sztmp += str.charAt(currentPos);
                    currentPos++;
                }

                // Handle square root (√)
                let num = "";
                if (sztmp.charAt(0) == "√") {
                    for (let i = 1; i < sztmp.length; i++) {
                        if (sztmp.charAt(i) == "^") {
                            break;
                        }
                        num += sztmp.charAt(i);
                    }
                    num = Math.sqrt(Number(num)).toString();
                    const sztmpArr_ = sztmp.split("^");
                    sztmpArr_[0] = num;
                    sztmp = "";
                    for (let i = 0; i < sztmpArr_.length; i++) {
                        sztmp += sztmpArr_[i] + "^";
                    }
                }

                // Handle power ^
                let sztmpArr = sztmp.split("^");
                if (sztmpArr.length >= 2) {
                    let tmpFun = "";
                    if (sztmp.search(/[a-zA-z]/) !== -1) {
                        const end = sztmp.search(/\d/);
                        for (let i = 0; i < end; i++) {
                            tmpFun += sztmp.charAt(i);
                        }
                        sztmp = sztmp.replace(tmpFun, "");
                        sztmpArr = sztmp.split("^");
                    }
                    let val = sztmpArr[sztmpArr.length - 1];
                    for (let i = sztmpArr.length - 2; i >= 0; i--) {
                        val = Math.pow(Number(sztmpArr[i]), Number(val)).toString();
                    }
                    sztmp = tmpFun + val;
                }

                // Handle trigonometric functions
                let start = 0;
                while (start > -1) {
                    start = sztmp.search(/sin\s*\d+/g) + 3;
                    if (start == 2) {
